<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cron-setup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 05:00</span></span>
